@* Displays a single task card with move buttons *@

<div class="task-card">
    <h4 class="task-title">@Task.Title</h4>
    <p class="task-assignee">@Task.Assignee</p>
    <span class="priority-badge priority-@Task.Priority.ToLowerInvariant()">@Task.Priority</span>
    <span class="task-due-date">@Task.DueDate.ToString("MMM dd")</span>
    <div class="task-actions">
        @if (ShowMoveLeft)
        {
            <button class="btn-move" @onclick="OnMoveLeft">Move Left</button>
        }
        @if (ShowMoveRight)
        {
            <button class="btn-move" @onclick="OnMoveRight">Move Right</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }
}

@* Inline form for creating a new task within a column *@

<div class="add-task-form">
    <input type="text" placeholder="Title" @bind="title" />
    <input type="text" placeholder="Assignee" @bind="assignee" />
    <select @bind="priority">
        <option value="High">High</option>
        <option value="Medium">Medium</option>
        <option value="Low">Low</option>
    </select>
    <input type="date" @bind="dueDate" />
    <div class="form-actions">
        <button class="btn-save" @onclick="HandleSave">Save</button>
        <button class="btn-cancel" @onclick="OnCancel">Cancel</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<NewTaskModel> OnSave { get; set; }
    [Parameter, EditorRequired] public EventCallback OnCancel { get; set; }

    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);

    private async Task HandleSave()
    {
        if (string.IsNullOrWhiteSpace(title)) return;
        await OnSave.InvokeAsync(new NewTaskModel(title, assignee, priority, dueDate));
    }

    public record NewTaskModel(string Title, string Assignee, string Priority, DateTime DueDate);
}

@* A single Kanban column: header, task cards, and optional add-task form *@

<div class="kanban-column">
    <div class="column-header">
        <h3>@ColumnName (@Tasks.Count)</h3>
    </div>

    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="ShowMoveLeft"
                      ShowMoveRight="ShowMoveRight"
                      OnMoveLeft="() => OnMoveLeft.InvokeAsync(task.Id)"
                      OnMoveRight="() => OnMoveRight.InvokeAsync(task.Id)" />
        }
    </div>

    <div class="column-footer">
        @if (showForm)
        {
            <AddTaskForm OnSave="HandleSave" OnCancel="() => showForm = false" />
        }
        else
        {
            <button class="btn-add-task" @onclick="() => showForm = true">Add Task</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = string.Empty;
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<int> OnMoveRight { get; set; }
    [Parameter] public EventCallback<AddTaskForm.NewTaskModel> OnAddTask { get; set; }

    private bool showForm;

    private async Task HandleSave(AddTaskForm.NewTaskModel model)
    {
        await OnAddTask.InvokeAsync(model);
        showForm = false;
    }
}

@* Summary statistics bar shown above the Kanban columns *@

<div class="board-stats">
    <span class="stat">Total: @Total</span>
    <span class="stat">To Do: @ToDo</span>
    <span class="stat">In Progress: @InProgress</span>
    <span class="stat">Done: @DoneCount</span>
    <span class="stat stat-overdue">Overdue: @Overdue</span>
</div>

@code {
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();

    private int Total => Tasks.Count;
    private int ToDo => Tasks.Count(t => t.Status == "To Do");
    private int InProgress => Tasks.Count(t => t.Status == "In Progress");
    private int DoneCount => Tasks.Count(t => t.Status == "Done");
    private int Overdue => Tasks.Count(t => t.DueDate < DateTime.Today && t.Status != "Done");
}

@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

@if (loading)
{
    <p class="loading-message">Loading board...</p>
}
else if (errorMessage is not null)
{
    <p class="error-message">@errorMessage</p>
}
else
{
    <BoardStats Tasks="tasks" />

    <div class="search-bar">
        <input type="text" placeholder="Search tasks by title..." @bind="searchText" @bind:event="oninput" />
    </div>

    <div class="kanban-board">
        <KanbanColumn ColumnName="To Do"
                      Tasks="GetFilteredTasks("To Do")"
                      ShowMoveLeft="false"
                      ShowMoveRight="true"
                      OnMoveRight="id => MoveTask(id, "In Progress")"
                      OnAddTask="model => AddTask(model, "To Do")" />

        <KanbanColumn ColumnName="In Progress"
                      Tasks="GetFilteredTasks("In Progress")"
                      ShowMoveLeft="true"
                      ShowMoveRight="true"
                      OnMoveLeft="id => MoveTask(id, "To Do")"
                      OnMoveRight="id => MoveTask(id, "Done")"
                      OnAddTask="model => AddTask(model, "In Progress")" />

        <KanbanColumn ColumnName="Done"
                      Tasks="GetFilteredTasks("Done")"
                      ShowMoveLeft="true"
                      ShowMoveRight="false"
                      OnMoveLeft="id => MoveTask(id, "In Progress")"
                      OnAddTask="model => AddTask(model, "Done")" />
    </div>
}

@code {
    private List<TaskItem> tasks = new();
    private string searchText = string.Empty;
    private bool loading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            tasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            loading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var filtered = tasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            filtered = filtered.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return filtered.ToList();
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = tasks.First(t => t.Id == taskId);
            tasks = tasks.Select(t => t.Id == taskId
                ? task with { Status = newStatus }
                : t).ToList();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task AddTask(AddTaskForm.NewTaskModel model, string status)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(model.Title, model.Assignee, model.Priority, model.DueDate);
            // CreateTaskAsync returns a task with default status; ensure it matches the column
            tasks.Add(newTask with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

