.board-stats {
    display: flex;
    gap: 1.5rem;
    padding: 1rem;
    background: #f8f9fa;
    border-radius: 8px;
    margin-bottom: 1rem;
    flex-wrap: wrap;
}

.board-stats .stat {
    font-weight: 600;
    font-size: 0.9rem;
}

.board-stats .stat-overdue {
    color: #dc3545;
}

.search-bar {
    margin-bottom: 1rem;
}

.search-bar input {
    width: 100%;
    max-width: 400px;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    font-size: 0.9rem;
}

.kanban-board {
    display: flex;
    gap: 1rem;
    align-items: flex-start;
}

.kanban-column {
    flex: 1;
    background: #f1f3f5;
    border-radius: 8px;
    padding: 1rem;
    min-width: 250px;
}

.column-header h3 {
    margin: 0 0 0.75rem;
    font-size: 1rem;
}

.column-body {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    min-height: 100px;
}

.task-card {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 0.75rem;
}

.task-title {
    margin: 0 0 0.25rem;
    font-size: 0.95rem;
}

.task-assignee {
    margin: 0 0 0.5rem;
    font-size: 0.8rem;
    color: #6c757d;
}

.priority-badge {
    display: inline-block;
    padding: 0.15rem 0.5rem;
    border-radius: 4px;
    font-size: 0.75rem;
    font-weight: 600;
    color: #fff;
    margin-right: 0.5rem;
}

.priority-high {
    background-color: #dc3545;
}

.priority-medium {
    background-color: #ffc107;
    color: #212529;
}

.priority-low {
    background-color: #28a745;
}

.task-due-date {
    font-size: 0.8rem;
    color: #495057;
}

.task-actions {
    margin-top: 0.5rem;
    display: flex;
    gap: 0.25rem;
}

.btn-move {
    padding: 0.2rem 0.5rem;
    font-size: 0.75rem;
    border: 1px solid #6c757d;
    border-radius: 4px;
    background: #fff;
    cursor: pointer;
}

.btn-move:hover {
    background: #e9ecef;
}

.column-footer {
    margin-top: 0.75rem;
}

.btn-add-task {
    width: 100%;
    padding: 0.4rem;
    border: 1px dashed #adb5bd;
    border-radius: 6px;
    background: transparent;
    cursor: pointer;
    font-size: 0.85rem;
    color: #495057;
}

.btn-add-task:hover {
    background: #e9ecef;
}

.add-task-form {
    display: flex;
    flex-direction: column;
    gap: 0.4rem;
    background: #fff;
    padding: 0.75rem;
    border-radius: 6px;
    border: 1px solid #dee2e6;
}

.add-task-form input,
.add-task-form select {
    padding: 0.35rem 0.5rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    font-size: 0.85rem;
}

.form-actions {
    display: flex;
    gap: 0.5rem;
}

.btn-save {
    padding: 0.3rem 0.75rem;
    background: #0d6efd;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.8rem;
}

.btn-cancel {
    padding: 0.3rem 0.75rem;
    background: #6c757d;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.8rem;
}

.loading-message,
.error-message {
    padding: 1rem;
    font-size: 1rem;
}

.error-message {
    color: #dc3545;
}

